function(wrap, spec) {
  // Set a default height only if the parent hasn't set one
  if (!wrap.style.height) wrap.style.height = '400px';

  // Helper to load a CDN script once
  function load(url, globalName, callback) {
    if (window[globalName]) { callback(); return; }
    var s = document.createElement('script');
    s.src = url;
    s.onload = callback;
    document.head.appendChild(s);
  }

  // Load your charting library, then render
  load(
    'https://cdn.jsdelivr.net/npm/YOUR-LIBRARY@VERSION/dist/lib.min.js',
    'YourLibraryGlobal',
    function() {
      // TODO: replace this block with your rendering code
      // spec.title, spec.requiredField1, spec.requiredField2, etc.
      var el = document.createElement('div');
      el.textContent = 'Replace this with your chart — spec.title: ' + (spec.title || '(none)');
      wrap.appendChild(el);
    }
  );
}
